using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResource
{
    [McpServerResource(UriTemplate = "config://app/settings", Name = "App Settings",
        MimeType = "application/json"), Description("Returns application configuration data")]
    public static string GetAppSettings()
    {
        var config = new
        {
            Environment = "production",
            MaxRetries = 3,
            TimeoutSeconds = 30,
            Features = new { DarkMode = true, BetaAccess = false }
        };

        return JsonSerializer.Serialize(config, new JsonSerializerOptions { WriteIndented = true });
    }
}

using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Updates a configuration value by key.")]
    public static string UpdateConfig(
        [Description("The configuration key to update")] string key,
        [Description("The new value to set")] string value)
    {
        // In a real app, persist to a config store
        return $"Configuration '{key}' updated to '{value}'.";
    }
}

